function CardGrid({ onScan }) {
  return (
    <div className="card-grid">
      {CARDS.map((c, i) => (
        c.rare === 'ghost' ? (
          <div key={i} className="tcard ghost" onClick={onScan}>
            <div className="ghost-mark">?</div>
            <div className="tcard-foot" style={{position:'static', padding:0}}>
              <span className="qty-tag">GHOST CARD</span>
              <span className="qty-tag" style={{background:'transparent', color:'var(--accent)', borderColor:'var(--accent)'}}>{c.qty}</span>
            </div>
          </div>
        ) : (
          <div key={i} className="tcard">
            <div className="tcard-art ph" data-name={c.name} style={{'--art-bg': c.art}}></div>
            <div className="tcard-name">{c.name.toUpperCase()}</div>
            <div className="tcard-foot">
              <span className={`rarity-tag ${c.rare}`}>{c.rare.toUpperCase()}</span>
              <span className="qty-tag">{c.qty}</span>
            </div>
          </div>
        )
      ))}
    </div>
  );
}

