function App() {
  const [t, setTweak] = useTweaks(TWEAK_DEFAULTS);
  const [active, setActive] = useState('mybinder');
  const [mobileOpen, setMobileOpen] = useState(false);
  const [toast, setToast] = useState(null);
  const [showAssumptions, setShowAssumptions] = useState(t.showAssumptions !== false);
  const [editLayout, setEditLayout] = useState(false);
  const [dragging, setDragging] = useState(null); // {id, region}

  // Apply accent override
  useEffect(() => {
    document.documentElement.style.setProperty('--accent', t.accent);
  }, [t.accent]);

  // Apply density via class on root for finer scaling
  useEffect(() => {
    const el = document.documentElement;
    el.classList.remove('density-comfy', 'density-compact', 'density-ref2');
    el.classList.add(`density-${t.panelDensity || 'comfy'}`);
  }, [t.panelDensity]);

  // Apply scanlines toggle
  useEffect(() => {
    document.body.style.setProperty('--scanlines-opacity', t.scanlines ? '0.35' : '0');
    const styleId = '__scanline-toggle';
    let s = document.getElementById(styleId);
    if (!s) { s = document.createElement('style'); s.id = styleId; document.head.appendChild(s); }
    s.textContent = `body::after { opacity: ${t.scanlines ? 0.35 : 0} !important; }`;
  }, [t.scanlines]);

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(()=>setToast(null), 2200);
  };

  const onScan = () => showToast('SCANNING CARD…');

  // ---- Layout helpers ----
  const hidden = t.panelHidden || {};
  const orders = {
    main:   t.panelOrderMain   || ['mybinder'],
    rail:   t.panelOrderRail   || ['summary', 'alerts'],
    bottom: t.panelOrderBottom || ['fund', 'trade', 'market'],
  };
  const orderKey = { main: 'panelOrderMain', rail: 'panelOrderRail', bottom: 'panelOrderBottom' };

  const visibleIn = (region) => orders[region].filter(id => !hidden[id]);

  const togglePanel = (id) => {
    setTweak('panelHidden', { ...hidden, [id]: !hidden[id] });
  };

  const resetLayout = () => {
    setTweak({
      panelOrderMain:   ['mybinder', 'fund', 'market'],
      panelOrderRail:   ['summary', 'alerts'],
      panelOrderBottom: [],
      panelHidden:      {trade: true},
    });
    showToast('LAYOUT RESET');
  };

  const handleDragStart = (id, region) => (e) => {
    if (!editLayout) return;
    setDragging({ id, region });
    e.dataTransfer.effectAllowed = 'move';
    try { e.dataTransfer.setData('text/plain', id); } catch(_) {}
  };
  const handleDragOver = (overId, region) => (e) => {
    if (!editLayout || !dragging) return;
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };
  const handleDrop = (overId, region) => (e) => {
    if (!editLayout || !dragging) return;
    e.preventDefault();
    const fromRegion = dragging.region;
    const fromId = dragging.id;
    if (fromRegion !== region) {
      setDragging(null);
      return; // keep cross-region moves out for now
    }
    const list = [...orders[region]];
    const fromIdx = list.indexOf(fromId);
    const toIdx = list.indexOf(overId);
    if (fromIdx === -1 || toIdx === -1 || fromIdx === toIdx) {
      setDragging(null);
      return;
    }
    list.splice(fromIdx, 1);
    list.splice(toIdx, 0, fromId);
    setTweak(orderKey[region], list);
    setDragging(null);
  };
  const handleDragEnd = () => setDragging(null);

  const renderPanel = (id, region) => {
    let inner = null;
    switch (id) {
      case 'mybinder': inner = <MyBinderPanel onScan={onScan} density={t.panelDensity} />; break;
      case 'summary':  inner = <CollectionSummary />; break;
      case 'alerts':   inner = <RecentAlertsPanel />; break;
      case 'fund':     inner = <CardFundWidget />; break;
      case 'trade':    inner = <TradeCheckWidget />; break;
      case 'market':   inner = <MarketActivityWidget />; break;
      default: return null;
    }
    const meta = PANEL_REGISTRY[id];
    return (
      <div
        key={id}
        className={`panel-slot ${editLayout ? 'editable' : ''} ${dragging && dragging.id === id ? 'is-dragging' : ''}`}
        draggable={editLayout}
        onDragStart={handleDragStart(id, region)}
        onDragOver={handleDragOver(id, region)}
        onDrop={handleDrop(id, region)}
        onDragEnd={handleDragEnd}
      >
        {editLayout && (
          <div className="slot-chrome">
            <span className="slot-handle" title="Drag to reorder">{Ico.grip || '⠿'}</span>
            <span className="slot-label">{meta.label}</span>
            <div style={{flex:1}}></div>
            <button className="slot-btn" onClick={()=>togglePanel(id)} title="Hide panel">{Ico.x}</button>
          </div>
        )}
        {inner}
      </div>
    );
  };

  const hiddenList = Object.keys(PANEL_REGISTRY).filter(id => hidden[id]);

  return (
    <div className={`app ${t.sidebarCollapsed ? 'sb-collapsed' : ''} ${mobileOpen ? 'mobile-open' : ''} ${editLayout ? 'editing-layout' : ''}`}>
      <div className="mobile-backdrop" onClick={()=>setMobileOpen(false)}></div>
      <Sidebar
        collapsed={t.sidebarCollapsed}
        onToggle={()=>setTweak('sidebarCollapsed', !t.sidebarCollapsed)}
        active={active}
        setActive={(id)=>{ setActive(id); showToast(`→ ${id.toUpperCase()}`); }}
        mobileOpen={mobileOpen}
        onMobileClose={()=>setMobileOpen(false)}
      />
      <div className="main">
        <Topbar onMobileToggle={()=>setMobileOpen(v=>!v)} />
        <div className="content">

          {showAssumptions && (
            <div className="assumptions">
              <div style={{flex:1}}>
                <strong>★ Designer notes</strong>
                <p>Combines reference 1's dashboard layout (stat ribbon · 2-col grid · 3-up widget row) with reference 2's collapsible left sidebar nav. Carries existing brutalist DNA — Orbitron + Space Mono + Press Start 2P, hard black drop-shadows, square corners, pixel grid bg.</p>
                <p style={{marginTop:6}}>Click <strong style={{color:'var(--accent)'}}>EDIT LAYOUT</strong> below to drag panels into a new order, hide ones you don't want, or restore the defaults. Open Tweaks (top toolbar) for theme + density.</p>
              </div>
              <button className="assumptions-close" onClick={()=>setShowAssumptions(false)} title="Dismiss">{Ico.x}</button>
            </div>
          )}

          <div className="page-head">
            <div>
              <div className="page-title-flair">DASHBOARD · LIVE</div>
              <div className="page-title">
                <h1>MY <span className="accent">BINDER</span></h1>
              </div>
            </div>
            <div className="page-actions">
              <button
                className={`pa-btn ${editLayout ? 'primary' : ''}`}
                onClick={()=>setEditLayout(v=>!v)}
                title="Drag panels to reorder, X to hide"
              >{Ico.grid} {editLayout ? 'DONE EDITING' : 'EDIT LAYOUT'}</button>
              {editLayout && (
                <button className="pa-btn" onClick={resetLayout} title="Restore defaults">{Ico.x} RESET</button>
              )}
              <button className="pa-btn">{Ico.filter} FILTER</button>
              <button className="pa-btn">{Ico.download} EXPORT</button>
              <button className="pa-btn primary">{Ico.scan} SCAN CARDS</button>
            </div>
          </div>

          {editLayout && hiddenList.length > 0 && (
            <div className="hidden-tray">
              <span className="ht-label">HIDDEN PANELS:</span>
              {hiddenList.map(id => (
                <button key={id} className="ht-chip" onClick={()=>togglePanel(id)} title="Restore">
                  + {PANEL_REGISTRY[id].label}
                </button>
              ))}
            </div>
          )}

          <StatRibbon showCityRibbon={t.showCityRibbon} />

          <div className="dash-grid">
            <div className="region-main">
              {(() => {
                const ids = visibleIn('main');
                const out = [];
                let buffer = [];
                const flushRow = () => {
                  if (buffer.length === 0) return;
                  out.push(
                    <div key={`row-${out.length}`} className="main-subrow">
                      {buffer.map(id => renderPanel(id, 'main'))}
                    </div>
                  );
                  buffer = [];
                };
                ids.forEach(id => {
                  if (id === 'mybinder') {
                    flushRow();
                    out.push(renderPanel(id, 'main'));
                  } else {
                    buffer.push(id);
                  }
                });
                flushRow();
                return out;
              })()}
            </div>
            <div className="region-rail">
              {visibleIn('rail').map(id => renderPanel(id, 'rail'))}
            </div>
          </div>

          {visibleIn('bottom').length > 0 && (
            <div className="widget-row">
              {visibleIn('bottom').map(id => renderPanel(id, 'bottom'))}
            </div>
          )}

        </div>
      </div>

      {toast && <div className="toast show">{toast}</div>}

      <TweaksPanel title="DASHBOARD TWEAKS">
        <TweakSection title="Theme">
          <TweakColor label="Accent" value={t.accent} onChange={v=>setTweak('accent', v)} />
          <TweakToggle label="Scanlines" value={t.scanlines} onChange={v=>setTweak('scanlines', v)} />
          <TweakToggle label="Cyber-skyline ribbon" value={t.showCityRibbon} onChange={v=>setTweak('showCityRibbon', v)} />
          <TweakToggle label="Show designer notes" value={showAssumptions} onChange={setShowAssumptions} />
        </TweakSection>
        <TweakSection title="Layout">
          <TweakToggle label="Collapse sidebar" value={t.sidebarCollapsed} onChange={v=>setTweak('sidebarCollapsed', v)} />
          <TweakRadio label="Density" value={t.panelDensity} onChange={v=>setTweak('panelDensity', v)} options={[
            { value: 'comfy', label: 'Comfy' },
            { value: 'compact', label: 'Compact' },
            { value: 'ref2', label: 'Ref 2' }
          ]} />
          <TweakToggle label="Edit layout mode" value={editLayout} onChange={setEditLayout} />
          <TweakButton label="Reset panel order" onClick={resetLayout} />
        </TweakSection>
        <TweakSection title="Show / Hide panels">
          {Object.entries(PANEL_REGISTRY).map(([id, meta]) => (
            <TweakToggle
              key={id}
              label={meta.label}
              value={!hidden[id]}
              onChange={()=>togglePanel(id)}
            />
          ))}
        </TweakSection>
        <TweakSection title="Quick swatches">
          <div style={{display:'grid', gridTemplateColumns:'repeat(5, 1fr)', gap: 6}}>
            {['#C5FF3D', '#FF5C00', '#4DD0E1', '#FFD23F', '#B388FF'].map(c => (
              <button key={c} onClick={()=>setTweak('accent', c)}
                style={{height:28, background:c, border: t.accent===c ? '2px solid #fff' : '1.5px solid var(--border)', cursor:'pointer'}}
                title={c} />
            ))}
          </div>
        </TweakSection>
      </TweaksPanel>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById('root')).render(<App />);
